#include<bits/stdc++.h>
using namespace std;
long long nxt[100010],val[100010];
bool vis[100010],vis1[100010];
vector<long long> pre[100010];
void dfs(long long num)
{
	vis[num]=true;
	long long siz=pre[num].size();
	for(long long i=0;i<siz;i++)
	{
		if(!vis[pre[num][i]])
		{
			dfs(pre[num][i]);
		}
	}
}
int main()
{
	long long n;
	scanf("%lld",&n);
	for(long long i=1;i<=n;i++)
	{
		scanf("%lld%lld",&nxt[i],&val[i]);
		pre[nxt[i]].push_back(i);
	}
	long long sum=0;
	for(long long i=1;i<=n;i++)
	{
		sum+=val[i];
	}
	for(long long i=1;i<=n;i++)
	{
		if(!vis[i])
		{
			long long x=i,min1=INT_MAX;
			while(!vis1[x])
			{
				vis1[x]=1;
				x=nxt[x];
			}
			long long v=x;
			min1=min(min1,val[v]);
			v=nxt[v];
			while(v!=x)
			{
				min1=min(min1,val[v]);
				v=nxt[v];
			}
			sum-=min1;
			dfs(x);
		}
	}
	printf("%lld",sum);
	return 0;
}
